import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Agent Gateway","description":"","frontmatter":{},"headers":[],"relativePath":"agentops/agent_gateway.md","filePath":"agentops/agent_gateway.md","lastUpdated":1783462857000}'),n={name:"agentops/agent_gateway.md"};function i(r,e,l,c,d,p){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="agent-gateway" tabindex="-1">Agent Gateway <a class="header-anchor" href="#agent-gateway" aria-label="Permalink to &quot;Agent Gateway&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Documentation in progress</p><p>This page is an early outline. Full Agent Gateway documentation is still being written and will be added here.</p></div><p>Agent Gateway provides the external API access layer for AgentOps and selected MLOps workflows.</p><p>It is not only an agent feature. The same gateway model can protect sandbox APIs, MCP servers, agent endpoints, and classic model-serving endpoints.</p><h2 id="what-it-does" tabindex="-1">What It Does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What It Does&quot;">​</a></h2><ul><li>Exposes public API path families such as <code>/sandbox</code>, <code>/mcp</code>, <code>/a2a</code>, <code>/ai</code>, and <code>/serving</code>.</li><li>Enforces scoped API-key access.</li><li>Routes requests to workspace-scoped backends.</li><li>Keeps public API access separate from browser-based UI login.</li></ul><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Calling model-serving endpoints from external applications.</li><li>Giving an agent access to a sandbox API without giving it browser credentials.</li><li>Exposing MCP servers to external agent clients.</li><li>Separating workspace and route scopes for automation clients.</li></ul><h2 id="api-keys" tabindex="-1">API Keys <a class="header-anchor" href="#api-keys" aria-label="Permalink to &quot;API Keys&quot;">​</a></h2><p>API keys are managed through pkui. The current Python and TypeScript SDKs send API keys as <code>x-api-key</code>. Bearer-style keys are not the SDK default right now.</p><p>Do not store API keys in source code, notebooks, screenshots, tickets, or chat messages.</p>',11)])])}const u=a(n,[["render",i]]);export{h as __pageData,u as default};
